create extension if not exists pgcrypto with schema extensions;
create or replace function public.set_updated_at() returns trigger language plpgsql security invoker set search_path='' as $$ begin new.updated_at=timezone('utc',now());return new;end;$$;
create table public.profiles(user_id uuid primary key references auth.users(id) on delete cascade,display_name text check(char_length(display_name)<=80),avatar_url text check(avatar_url is null or char_length(avatar_url)<=2048),preferred_theme text not null default 'system' check(preferred_theme in('light','dark','system')),created_at timestamptz not null default timezone('utc',now()),updated_at timestamptz not null default timezone('utc',now()));
create table public.model_runs(id uuid primary key default extensions.gen_random_uuid(),user_id uuid not null references public.profiles(user_id) on delete cascade,model_key text not null check(model_key~'^[a-z0-9-]{2,64}$'),name text not null check(char_length(name) between 1 and 120),parameters jsonb not null default '{}'::jsonb check(jsonb_typeof(parameters)='object'),results jsonb not null default '{}'::jsonb check(jsonb_typeof(results)='object'),notes text check(notes is null or char_length(notes)<=2000),created_at timestamptz not null default timezone('utc',now()),updated_at timestamptz not null default timezone('utc',now()));
create table public.favorites(id uuid primary key default extensions.gen_random_uuid(),user_id uuid not null references public.profiles(user_id) on delete cascade,model_key text not null check(model_key~'^[a-z0-9-]{2,64}$'),created_at timestamptz not null default timezone('utc',now()),updated_at timestamptz not null default timezone('utc',now()),unique(user_id,model_key));
create table public.learning_progress(id uuid primary key default extensions.gen_random_uuid(),user_id uuid not null references public.profiles(user_id) on delete cascade,model_key text not null check(model_key~'^[a-z0-9-]{2,64}$'),status text not null default 'not_started' check(status in('not_started','in_progress','completed')),progress_percent smallint not null default 0 check(progress_percent between 0 and 100),last_parameters jsonb not null default '{}'::jsonb check(jsonb_typeof(last_parameters)='object'),last_visited_at timestamptz,completed_at timestamptz,created_at timestamptz not null default timezone('utc',now()),updated_at timestamptz not null default timezone('utc',now()),unique(user_id,model_key),check(completed_at is null or status='completed'));
create index model_runs_user_created_idx on public.model_runs(user_id,created_at desc);create index model_runs_user_model_idx on public.model_runs(user_id,model_key,updated_at desc);create index model_runs_parameters_gin_idx on public.model_runs using gin(parameters);create index favorites_user_created_idx on public.favorites(user_id,created_at desc);create index learning_progress_user_status_idx on public.learning_progress(user_id,status,updated_at desc);
create trigger profiles_set_updated_at before update on public.profiles for each row execute function public.set_updated_at();create trigger model_runs_set_updated_at before update on public.model_runs for each row execute function public.set_updated_at();create trigger favorites_set_updated_at before update on public.favorites for each row execute function public.set_updated_at();create trigger learning_progress_set_updated_at before update on public.learning_progress for each row execute function public.set_updated_at();
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path='' as $$ begin insert into public.profiles(user_id,display_name,avatar_url) values(new.id,nullif(left(coalesce(new.raw_user_meta_data->>'display_name',''),80),''),nullif(left(coalesce(new.raw_user_meta_data->>'avatar_url',''),2048),'')) on conflict(user_id) do nothing;return new;end;$$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
alter table public.profiles enable row level security;alter table public.model_runs enable row level security;alter table public.favorites enable row level security;alter table public.learning_progress enable row level security;
create policy "profiles_select_own" on public.profiles for select to authenticated using((select auth.uid())=user_id);create policy "profiles_insert_own" on public.profiles for insert to authenticated with check((select auth.uid())=user_id);create policy "profiles_update_own" on public.profiles for update to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);create policy "profiles_delete_own" on public.profiles for delete to authenticated using((select auth.uid())=user_id);
create policy "model_runs_select_own" on public.model_runs for select to authenticated using((select auth.uid())=user_id);create policy "model_runs_insert_own" on public.model_runs for insert to authenticated with check((select auth.uid())=user_id);create policy "model_runs_update_own" on public.model_runs for update to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);create policy "model_runs_delete_own" on public.model_runs for delete to authenticated using((select auth.uid())=user_id);
create policy "favorites_select_own" on public.favorites for select to authenticated using((select auth.uid())=user_id);create policy "favorites_insert_own" on public.favorites for insert to authenticated with check((select auth.uid())=user_id);create policy "favorites_update_own" on public.favorites for update to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);create policy "favorites_delete_own" on public.favorites for delete to authenticated using((select auth.uid())=user_id);
create policy "progress_select_own" on public.learning_progress for select to authenticated using((select auth.uid())=user_id);create policy "progress_insert_own" on public.learning_progress for insert to authenticated with check((select auth.uid())=user_id);create policy "progress_update_own" on public.learning_progress for update to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);create policy "progress_delete_own" on public.learning_progress for delete to authenticated using((select auth.uid())=user_id);
revoke all on function public.handle_new_user() from public,anon,authenticated;grant execute on function public.set_updated_at() to authenticated;grant usage on schema public to anon,authenticated;grant select,insert,update,delete on public.profiles,public.model_runs,public.favorites,public.learning_progress to authenticated;
